jsonrpc.code:
// → Client: list tools
{"jsonrpc":"2.0","id":1,"method":"tools/list","params":{}}

// ← Server: tool schema
{"jsonrpc":"2.0","id":1,"result":{"tools":[{"name":"get_current_time","description":"Returns current time in a given timezone","inputSchema":{"type":"object","properties":{"timezone":{"type":"string"}}}}]}}

// → Client: call tool (LLM decided to invoke it)
{"jsonrpc":"2.0","id":2,"method":"tools/call","params":{"name":"get_current_time","arguments":{"timezone":"Europe/Kyiv"}}}

// ← Server: result
{"jsonrpc":"2.0","id":2,"result":{"content":[{"type":"text","text":"2026-05-11 11:30:00 EEST"}]}}
